scwin.sbm_saveAsetNo_submitdone = function (e) {
    $c.gus.cfAlertMsg(MSG_CM_INF_001);
    $c.gus.cfDisableKeyData();

    //$c.gus.cfDisableBtn([bSave]);  
    $c.gus.cfDisableBtn([btn_Upt]);  
	ed_nonledgerAsetNo2.setValue("");
    ds_asetNo.removeAll();
    scwin.f_Retrieve();
};
scwin.sbm_saveAsetNo_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
    $c.gus.cfEnableKeyData();
    $c.gus.cfDisableBtn([ btn_Add]);
};

scwin.sbm_search_submitdone = function (e) {
    //cfHideDSWaitMsg(gr_asetNo);
    let rowCnt = ds_asetNo.getRowCount();
    ed_totalRows.setValue( rowCnt );

    if( rowCnt == 0 ){
		$c.gus.cfAlertMsg(MSG_CM_WRN_002);
		ds_asetDetailNo.removeAll();
	} else {
        ds_asetNo.setRowPosition(0);
        gr_asetNo.setFocusedCell(0, 0, false);
		scwin.f_RetrieveAsetHistory("0");
		scwin.txt_orgTransferDt = ds_asetNo.getCellData(0, "orgTransferDt");
	}

    if(ds_asetNo.getCellData(0,"disuseDt") != ""){
		$c.gus.cfDisableBtnOnly([ btn_Trans, btn_Dis, btn_Add, btn_Upt, btn_Cancel, bCancel ]);
	} else {
     	$c.gus.cfDisableBtnOnly([ btn_Upt, btn_Cancel, bCancel ]);
		$c.gus.cfEnableBtnOnly([ btn_Trans, btn_Dis, btn_Add ]); //저장버튼
	}

	ed_nonledgerAsetNo2.setValue("");
};
