//-------------------------------------------------------------------------
// 체크
//-------------------------------------------------------------------------
scwin.f_Validation = async function() {
    let ret;
    ret = await $c.gus.cfValidate([ed_nonledgerAset, ed_nonledgerAsetNm,ed_asetNm,ed_acqDeptCd,ed_acqDeptNm,ed_acqDt
                    , ed_acqAmt, ed_userNm, ed_procAcct, ed_acctNm]);   
                    //invalidMessag 체크부분이 오동작 하여 잠시 빼둠 ed_rmk, ed_disuseDt   //1205 oyj

    if (!ret)
        return false;


    if(ed_disuseDt.getValue().trim()==""){
        //txt_disuseRsn.validExp="폐기사유:no"; 
        ed_disuseRsn.options.mandatory = false;
        ed_disuseRsn.setUserData("invalidMessage", "");

    }
    else if (ed_disuseDt.getValue().trim()!=""){
        //txt_disuseRsn.validExp="폐기사유:yes"; 
        ed_disuseRsn.options.mandatory = true;
        ed_disuseRsn.setUserData("invalidMessage", "폐기사유");
        //console.log("동적으로 invalidMessage 를 ...");
        ret = await $c.gus.cfValidate([ed_disuseRsn]) ;
        if (!ret) return false;
    }

    if((ed_disuseDt.getValue().trim()=="") && ed_disuseRsn.getValue().trim()!=""){
        $c.win.alert("폐기일자가 없을 경우  폐기사유를 입력할 수 없습니다.");
        return false;
    }

    return true;
}

