scwin.f_WholeAdoption = async function(){

    if(ds_asetNo.getModifiedIndex().length < 1){
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, Array("자료"));
    }

    let ret;
    ret = await scwin.f_Validation();
    if (!ret)
    return ;


    if (ed_nonledgerAsetNo2.getValue().trim()=="" || ed_nonledgerAsetNo2.getValue() == '0'){
        $c.win.alert("수량을 입력해주세요");
        return;
    } 

    let currentRow = ds_asetNo.getRowPosition();
    let newRow;
    for ( var i = 0 ; i < ed_nonledgerAsetNo2.getValue(); i ++) {
        scwin.isAdoption = true;

        newRow = ds_asetNo.insertRow();
        ds_asetNo.setRowPosition(newRow);

        //length = ds_asetNo.NameValue(currentRow,"nonledgerAsetNo").length;
        ds_asetNo.setCellData(newRow, "goodsNm",       ds_asetNo.getCellData(currentRow, "goodsNm"));
        ds_asetNo.setCellData(newRow, "goodsCd",       ds_asetNo.getCellData(currentRow, "goodsCd"));
        ds_asetNo.setCellData(newRow, "asetNm",        ds_asetNo.getCellData(currentRow, "asetNm"));
        ds_asetNo.setCellData(newRow, "acqDeptCd",     ds_asetNo.getCellData(currentRow, "acqDeptCd"));
        ds_asetNo.setCellData(newRow, "acqDeptNm",     ds_asetNo.getCellData(currentRow, "acqDeptNm"));
        ds_asetNo.setCellData(newRow, "acqDt",         ds_asetNo.getCellData(currentRow, "acqDt"));
        ds_asetNo.setCellData(newRow, "acqAmt",        ds_asetNo.getCellData(currentRow, "acqAmt"));
        ds_asetNo.setCellData(newRow, "userNm",        ds_asetNo.getCellData(currentRow, "userNm"));
        ds_asetNo.setCellData(newRow, "acctCd",        ds_asetNo.getCellData(currentRow, "acctCd"));
        ds_asetNo.setCellData(newRow, "acctNm",        ds_asetNo.getCellData(currentRow, "acctNm"));
        ds_asetNo.setCellData(newRow, "rmk",           ds_asetNo.getCellData(currentRow, "rmk"));
        ds_asetNo.setCellData(newRow, "disuseDt",      ds_asetNo.getCellData(currentRow, "disuseDt"));
        ds_asetNo.setCellData(newRow, "disuseRsn",     ds_asetNo.getCellData(currentRow, "disuseRsn"));
        ds_asetNo.setCellData(newRow, "transferDt",    ds_asetNo.getCellData(currentRow, "transferDt"));
        ds_asetNo.setCellData(newRow, "modId",         ds_asetNo.getCellData(currentRow, "modId"));
        ds_asetNo.setCellData(newRow, "modDtm",        ds_asetNo.getCellData(currentRow, "modDtm"));
        ds_asetNo.setCellData(newRow, "regId",         ds_asetNo.getCellData(currentRow, "regId"));
        ds_asetNo.setCellData(newRow, "regDtm",        ds_asetNo.getCellData(currentRow, "regDtm"));
        ds_asetNo.setCellData(newRow, "orgAcqDeptCd",  ds_asetNo.getCellData(currentRow, "orgAcqDeptCd"));


        $c.gus.cfEnableBtnOnly([ btn_Upt, btn_Cancel, bCancel ]);
        $c.gus.cfDisableBtnOnly([ btn_Trans, btn_Dis, btn_Add ]);  

        scwin.isAdoption = false; 	
    }      
}	

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function() {
    //alert(ds_asetNo.NameValue(ds_asetNo.RowPosition, "useYn"));
    //alert(ds_asetNo.getValue);   	
    //변경한 데이터가 있는지 체크한다. 
    if(ds_asetNo.getModifiedIndex().length < 1){
        $c.gus.cfAlertMsg(MSG_CM_ERR_001,Array("데이타"));
        return;
    }  

    let rowPosi = ds_asetNo.getRowPosition();
    let ret;

    ds_asetNo.setCellData(rowPosi, "saveType", scwin.txt_saveType);
    let orgTransferDt = scwin.txt_orgTransferDt;

    // 이관시 사용부서 변경 여부 
    if(scwin.txt_saveType == "2") { 
        let org_dep = ds_asetNo.getOriginalCellData(rowPosi, "acqDeptCd");
        var new_dep = ds_asetNo.getCellData(rowPosi, "acqDeptCd");
        if(org_dep == new_dep) {
            $c.gus.cfAlertMsg(MSG_CM_ERR_001,Array("사용부서"));
            return;
        }

        ret = await $c.gus.cfIsAfterDate(ed_acqDt.getValue(),ed_transDt.getValue(), true);
        if (!ret) {
            $c.gus.cfAlertMsg("이관일자는 취득일자 보다 이후 날짜 이어야 합니다.");
            ed_transDt.focus();
            return;
        }

        ret = await $c.gus.cfIsAfterDate(orgTransferDt,ed_transDt.getValue(), true);
        if (!ret) {
            $c.gus.cfAlertMsg("새로운 이관일자는 이전 이관일자 보다 이후 날짜 이어야 합니다.");
            ed_transDt.focus();
            return;
        }
    }
    else if(scwin.txt_saveType == "1") { 
        ret = await $c.gus.cfIsAfterDate(orgTransferDt,ed_disuseDt.getValue(), true);
        if (!ret) {
            $c.gus.cfAlertMsg("폐기일자는 이관일자 보다 이후 날짜 이어야 합니다.");
            ed_disuseDt.focus();
            return;
        }

        ret = await $c.gus.cfIsAfterDate(ed_acqDt.getValue(),ed_disuseDt.getValue(), true);
        if (!ret) {
            $c.gus.cfAlertMsg("폐기일자는 취득일자 보다 이후 날짜 이어야 합니다.");
            ed_disuseDt.focus();
            return;
        }
    }

    // 체크
    ret = await scwin.f_Validation(); 
    if (!ret)
    return;

    ret = await $c.win.confirm("저장하시겠습니까?");
    if(ret==true){
        scwin.isSave = true;
        //tr_saveAsetNo.post();
        $c.sbm.execute(sbm_saveAsetNo);
        scwin.isSave = false;
    } 
}

