									    + "font-face:'돋움체';" // 폰트
									    + "font-size:18pt;"    // 폰트 크기
									    + "font-color:black;"  // 폰트 색깔
									    + "bgcolor:#ffffff;"   // 배경 색깔
									    + "align:center;"      // 정렬
									    + "line-color:white;"  // 타이틀 부분 테두리선 색깔
									    + "line-width:0pt;"    // 타이틀 테두리선 굵기
									    + "skiprow:1;");       // 타이틀 다음 떼는 로우 수

		fileName = '부외자산목록_' + txt_srchAcqDeptNmSt.value + "_" + txt_srchAcqDeptNmEnd.value;

		cfGridToExcel(gr_asetNo,fileName,fileName,2+8+16);
 * 
 * 
 */


    if(ds_asetDetailNo.getRowCount() < 1){
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return false;
    }
    let sheetTitle = "부외자산이관이력 (" + ed_srchAcqDeptNmSt.getValue() + " ~ " + ed_srchAcqDeptNmEnd.getValue() + ")";

    let gridId = gr_asetHistNo;
    let infoArr = [];
    let options = {
        fileName: "부외자산이관이력_" + ed_srchAcqDeptNmSt.getValue() + "_" + ed_srchAcqDeptNmEnd.getValue() + "" +'.xlsx',    // + ".xls",
        sheetName: sheetTitle,
        startRowIndex: 2
    };

    var calcaulatedColnum = 0;
    for(var idx =0; idx < ds_asetDetailNo.getTotalCol(); idx++ ){
        if(gr_asetHistNo.getColumnVisible(gr_asetHistNo.getColumnID(idx))) {
            calcaulatedColnum++;
        }
    }

    infoArr = [
        //제목
        {
              rowIndex: 0               //제목을 표시할 행 index
            , colIndex: 0               //제목을 표시할 열 index
            , rowSpan: 0                //병합할 행의 수
            , colSpan: calcaulatedColnum                //병합할 열의 수
            , text: sheetTitle          //표시할 내용(제목)
            , textAlign: "center"       //표시할 내용의 정렬 방법(left, center, right)
            , fontSize: "18px"          //폰트 size
            , fontName: "돋움체"        //폰트이름 
            , drawBorder: false       //cell의 border 지정(true, false)
            // ,useFooter:"true"        //다운로드시 Footer를 출력 할지 여부( "true"인경우 출력, "false"인경우 미출력)
        },

    ]; 

    await $c.data.downloadGridViewExcel(gridId, options, infoArr);

}
